import { Admin_board_members_View } from "../view/view.js";
import { Admin_board_members_Model } from "../model/model.js";

export class Admin_board_members_controller {
  constructor() {
    this.model = new Admin_board_members_Model();
    this.view = new Admin_board_members_View();

    this.model.registerListener((state) => {
      this.view.render_fetch_board_members(state);
    });

    this.model.registerListener((state) => {
      this.view.render_fetch_board_documents(state);
    });

    this.model.registerListener((state) => {
      this.view.render_add_board_members(state);
    });

    this.model.registerListener((state) => {
      this.view.render_edit_board_members(state);
    });

    this.model.registerListener((state) => {
      this.view.render_delete_board_members(state);
    });

    this.model.registerListener((state) => {
      this.view.render_add_board_documents(state);
    });

    this.model.registerListener((state) => {
      this.view.render_delete_board_documents(state);
    });

    this.view.articles_event_listener((index) => {
      if (index === 1) {
        this.model.fetch_board_members();
      }
      if (index === 2) {
        this.view.add_board_members(this.add_board_members);
      }
      if (index === 3) {
        this.model.fetch_board_members();
        this.view.delete_board_members(this.delete_board_members);
      }
      if (index === 4) {
        this.model.fetch_board_members();
        this.view.edit_board_members(this.edit_board_members);
      }
      if (index === 5) {
        this.model.fetch_board_documents();
      }
      if (index === 6) {
        this.view.add_board_documents(this.add_board_documents);
      }
      if (index === 7) {
        this.model.fetch_board_documents();
        this.view.delete_board_documents(this.delete_board_documents);
      }
    });
  }

  edit_board_members = (old_username, username, password) => {
    this.model.edit_board_members(old_username, username, password);
  };

  add_board_members = (username, password) => {
    this.model.add_board_members(username, password);
  };

  delete_board_members = (username) => {
    this.model.delete_board_member(username);
  };

  add_board_documents = (name, pdf) => {
    this.model.add_board_documents(name, pdf);
  };

  delete_board_documents = (document_name) => {
    this.model.delete_board_documents(document_name);
  };
}
